import React, { useEffect, useState } from 'react';
import { adminAPI } from '../../services/api';
import Card from '../../components/common/Card';
import { Search, Activity, User, Clock } from 'lucide-react';

const SystemLogs = () => {
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState({ action: '', limit: 100 });

  useEffect(() => {
    fetchLogs();
  }, [filters]);

  const fetchLogs = async () => {
    setLoading(true);
    try {
      const response = await adminAPI.getAuditLogs(filters);
      if (response.data.success) {
        setLogs(response.data.logs);
      }
    } catch (error) {
      console.error('Error fetching logs:', error);
    } finally {
      setLoading(false);
    }
  };

  const getActionColor = (action) => {
    if (action.includes('CREATE')) return 'bg-green-100 text-green-700';
    if (action.includes('UPDATE')) return 'bg-blue-100 text-blue-700';
    if (action.includes('DELETE')) return 'bg-red-100 text-red-700';
    if (action.includes('LOGIN') || action.includes('LOGOUT')) return 'bg-purple-100 text-purple-700';
    return 'bg-secondary-100 text-secondary-700';
  };

  return (
    <div className="space-y-6 animate-fade-in">
      <h1 className="text-2xl font-bold text-secondary-800">System Logs</h1>

      {/* Filters */}
      <Card>
        <div className="flex flex-wrap gap-4">
          <input
            type="text"
            value={filters.action}
            onChange={(e) => setFilters(prev => ({ ...prev, action: e.target.value }))}
            placeholder="Filter by action..."
            className="input-field w-auto"
          />
          <select
            value={filters.limit}
            onChange={(e) => setFilters(prev => ({ ...prev, limit: parseInt(e.target.value) }))}
            className="input-field w-auto"
          >
            <option value={50}>Last 50 entries</option>
            <option value={100}>Last 100 entries</option>
            <option value={200}>Last 200 entries</option>
            <option value={500}>Last 500 entries</option>
          </select>
        </div>
      </Card>

      {/* Logs Table */}
      <Card>
        {loading ? (
          <div className="text-center py-10">Loading...</div>
        ) : logs.length > 0 ? (
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="border-b border-secondary-200">
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Timestamp</th>
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">User</th>
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Action</th>
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Details</th>
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">IP Address</th>
                </tr>
              </thead>
              <tbody>
                {logs.map((log) => (
                  <tr key={log.id} className="border-b border-secondary-100 hover:bg-secondary-50">
                    <td className="py-3 px-4">
                      <div className="flex items-center gap-2">
                        <Clock className="w-4 h-4 text-secondary-400" />
                        {new Date(log.created_at).toLocaleString()}
                      </div>
                    </td>
                    <td className="py-3 px-4">
                      <div className="flex items-center gap-2">
                        <User className="w-4 h-4 text-secondary-400" />
                        <div>
                          <p className="font-medium">{log.username || 'System'}</p>
                          <p className="text-xs text-secondary-500">{log.role || ''}</p>
                        </div>
                      </div>
                    </td>
                    <td className="py-3 px-4">
                      <span className={`px-3 py-1 rounded-full text-sm ${getActionColor(log.action)}`}>
                        {log.action}
                      </span>
                    </td>
                    <td className="py-3 px-4 text-secondary-600 text-sm max-w-xs truncate">
                      {log.details ? JSON.stringify(log.details).substring(0, 50) + '...' : '-'}
                    </td>
                    <td className="py-3 px-4 text-secondary-500 text-sm">
                      {log.ip_address || '-'}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="text-center py-10 text-secondary-500">
            <Activity className="w-12 h-12 mx-auto mb-3 text-secondary-300" />
            <p>No logs found</p>
          </div>
        )}
      </Card>
    </div>
  );
};

export default SystemLogs;
